import{c as t,Q as i,j as r,m as a}from"./chunks/framework.rlpw0eGz.js";const g=JSON.parse('{"title":"🛠️ Extra Utilities Guide","description":"","frontmatter":{},"headers":[],"relativePath":"EXTRA.md","filePath":"EXTRA.md"}'),o={name:"EXTRA.md"};function s(n,e,l,c,d,u){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="🛠️-extra-utilities-guide" tabindex="-1">🛠️ Extra Utilities Guide <a class="header-anchor" href="#🛠️-extra-utilities-guide" aria-label="Permalink to &quot;🛠️ Extra Utilities Guide&quot;">​</a></h1><p>The <code>Extra/</code> directory contains a curated selection of lightweight, high-performance utilities, custom system configurators, and network tuning applications designed to optimize your workspace and reduce systemic latency.</p><hr><h2 id="🗃️-1-file-archiving-management" tabindex="-1">🗃️ 1. File Archiving &amp; Management <a class="header-anchor" href="#🗃️-1-file-archiving-management" aria-label="Permalink to &quot;🗃️ 1. File Archiving &amp; Management&quot;">​</a></h2><h3 id="_7-zip-7z2501-x64-exe-7z2501-exe" tabindex="-1">7-Zip (<code>7z2501-x64.exe</code> / <code>7z2501.exe</code>) <a class="header-anchor" href="#_7-zip-7z2501-x64-exe-7z2501-exe" aria-label="Permalink to &quot;7-Zip (`7z2501-x64.exe` / `7z2501.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Open-source, high-efficiency file archiver with a high compression ratio in the <code>.7z</code> format.</li><li><strong>Why Use</strong>: Completely free of advertising and nag-screens. Consumes significantly less memory during compression/decompression compared to standard WinZIP.</li></ul><h3 id="winrar-winrar-x64-623-exe" tabindex="-1">WinRAR (<code>winrar-x64-623.exe</code>) <a class="header-anchor" href="#winrar-winrar-x64-623-exe" aria-label="Permalink to &quot;WinRAR (`winrar-x64-623.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: High-fidelity file archiver with native support for the <code>.rar</code> format. Excellent for extracting split archives.</li></ul><h3 id="iobit-unlocker-iobit-unlocker" tabindex="-1">IObit Unlocker (<code>IObit Unlocker/</code>) <a class="header-anchor" href="#iobit-unlocker-iobit-unlocker" aria-label="Permalink to &quot;IObit Unlocker (`IObit Unlocker/`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Resolves issues where files or folders cannot be deleted because they are locked by background system services.</li><li><strong>How to Use</strong>: Right-click the locked file, select <strong>IObit Unlocker</strong>, and click <strong>Unlock &amp; Delete</strong> or <strong>Unlock &amp; Rename</strong>.</li></ul><h3 id="everything-everything-1-4-1-1024-x86-setup-exe" tabindex="-1">Everything (<code>Everything-1.4.1.1024.x86-Setup.exe</code>) <a class="header-anchor" href="#everything-everything-1-4-1-1024-x86-setup-exe" aria-label="Permalink to &quot;Everything (`Everything-1.4.1.1024.x86-Setup.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Fast search utility that indexes your system&#39;s NTFS file structures in seconds. It provides near-instant search results as you type, consuming negligible background memory.</li></ul><hr><h2 id="⚡-2-network-system-latency-tuning" tabindex="-1">⚡ 2. Network &amp; System Latency Tuning <a class="header-anchor" href="#⚡-2-network-system-latency-tuning" aria-label="Permalink to &quot;⚡ 2. Network &amp; System Latency Tuning&quot;">​</a></h2><h3 id="tcp-optimizer-tcpoptimizer-exe" tabindex="-1">TCP Optimizer (<code>TCPOptimizer.exe</code>) <a class="header-anchor" href="#tcp-optimizer-tcpoptimizer-exe" aria-label="Permalink to &quot;TCP Optimizer (`TCPOptimizer.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: A portable configurator designed to tune your TCP/IP parameters in the registry.</li><li><strong>Optimal Gaming Setup</strong>: <ol><li>Right-click <code>TCPOptimizer.exe</code> and select <strong>Run as administrator</strong>.</li><li>Drag the slider at the top to match your maximum internet connection speed.</li><li>Select the <strong>Optimal</strong> radio button at the bottom.</li><li>Click <strong>Apply Changes</strong>, check the backup box, and restart the PC to optimize MTU, TCP Window Auto-Tuning, and Nagle&#39;s Algorithm.</li></ol></li></ul><h3 id="msi-utility-v3-msi-utility-v3-exe" tabindex="-1">MSI Utility V3 (<code>MSI Utility V3.exe</code>) <a class="header-anchor" href="#msi-utility-v3-msi-utility-v3-exe" aria-label="Permalink to &quot;MSI Utility V3 (`MSI Utility V3.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Configures devices to use <strong>Message Signaled-Based Interrupts (MSI)</strong> instead of legacy Line-Based Interrupts (Pin-Based).</li></ul><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>MSI Optimization Steps (Reduces Audio Crackling &amp; GPU Latency)</strong>:</p><ol><li>Right-click <code>MSI Utility V3.exe</code> and select <strong>Run as administrator</strong>.</li><li>Locate your primary <strong>Graphics Card (GPU)</strong> in the hardware list.</li><li>Check the box in the <strong>MSI</strong> column for your GPU.</li><li>Change the <strong>Interrupt Priority</strong> column from &quot;Undefined&quot; or &quot;Normal&quot; to <strong>High</strong>.</li><li>Click <strong>Apply</strong> in the top right corner.</li><li><em>Warning</em>: Do not set priority to High for non-essential components (like USB or network adapters) as this can lead to system instability.</li></ol></div><hr><h2 id="🎨-3-system-customization" tabindex="-1">🎨 3. System Customization <a class="header-anchor" href="#🎨-3-system-customization" aria-label="Permalink to &quot;🎨 3. System Customization&quot;">​</a></h2><h3 id="winaero-tweaker-winaero-tweaker-exe" tabindex="-1">Winaero Tweaker (<code>Winaero Tweaker.exe</code>) <a class="header-anchor" href="#winaero-tweaker-winaero-tweaker-exe" aria-label="Permalink to &quot;Winaero Tweaker (`Winaero Tweaker.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: A comprehensive customization panel that allows you to safely toggle hidden Windows registry variables via a simple graphical interface.</li><li><strong>Key Optimizations</strong>: <ul><li>Disable automatic driver updates via Windows Update.</li><li>Disable lock screen ads, telemetry, and preloaded apps.</li><li>Enable classic shell features and right-click menus on Windows 11.</li></ul></li></ul><hr><h2 id="🔍-4-system-monitoring-diagnostics" tabindex="-1">🔍 4. System Monitoring &amp; Diagnostics <a class="header-anchor" href="#🔍-4-system-monitoring-diagnostics" aria-label="Permalink to &quot;🔍 4. System Monitoring &amp; Diagnostics&quot;">​</a></h2><h3 id="process-explorer-process-explorer-exe" tabindex="-1">Process Explorer (<code>Process Explorer.exe</code>) <a class="header-anchor" href="#process-explorer-process-explorer-exe" aria-label="Permalink to &quot;Process Explorer (`Process Explorer.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: An advanced Task Manager replacement by Sysinternals.</li><li><strong>Why Use</strong>: Displays detailed process trees, lets you view active DLL handles, maps CPU thread usage inside individual tasks, and integrates with VirusTotal to check running processes for malware.</li></ul><h3 id="serviwin-serviwin-exe" tabindex="-1">ServiWin (<code>serviwin.exe</code>) <a class="header-anchor" href="#serviwin-serviwin-exe" aria-label="Permalink to &quot;ServiWin (`serviwin.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Displays a clean, tabular list of all installed drivers and system services on your PC. It allows you to instantly stop, start, or change service startup configurations without navigating the Windows Services utility.</li></ul><hr><h2 id="⚙️-5-general-utilities" tabindex="-1">⚙️ 5. General Utilities <a class="header-anchor" href="#⚙️-5-general-utilities" aria-label="Permalink to &quot;⚙️ 5. General Utilities&quot;">​</a></h2><h3 id="restartdwm-restartdwm-exe" tabindex="-1">RestartDWM (<code>RestartDWM.exe</code>) <a class="header-anchor" href="#restartdwm-restartdwm-exe" aria-label="Permalink to &quot;RestartDWM (`RestartDWM.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Safely and instantly restarts the Desktop Window Manager (DWM) process.</li><li><strong>Why Use</strong>: Restarting DWM is highly useful for fixing visual glitches, resetting Multiplane Overlay (MPO) states, and clearing VRAM buffers to fix input latency without needing to reboot the entire PC.</li><li><strong><a href="https://github.com/YTxFSGAMERz/Windows-Optimisations/raw/master/RestartDWM.exe" class="md-button" target="_blank" rel="noreferrer">Download RestartDWM.exe</a></strong></li></ul><h3 id="rufus-rufus-3-22p-exe" tabindex="-1">Rufus (<code>rufus-3.22p.exe</code>) <a class="header-anchor" href="#rufus-rufus-3-22p-exe" aria-label="Permalink to &quot;Rufus (`rufus-3.22p.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Highly reliable utility to format and create bootable USB installation media from ISO images (used for clean unattended OS installations).</li></ul><h3 id="anydesk-anydesk-exe" tabindex="-1">AnyDesk (<code>AnyDesk.exe</code>) <a class="header-anchor" href="#anydesk-anydesk-exe" aria-label="Permalink to &quot;AnyDesk (`AnyDesk.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Fast, lightweight remote desktop software used to obtain remote assistance or manage secondary PCs on your network.</li></ul><h3 id="custom-resolution-utility-cru-cru-exe" tabindex="-1">Custom Resolution Utility - CRU (<code>CRU.exe</code>) <a class="header-anchor" href="#custom-resolution-utility-cru-cru-exe" aria-label="Permalink to &quot;Custom Resolution Utility - CRU (`CRU.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Bypasses EDID display limits to create custom desktop resolutions and refresh rates.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>Using CRU to Overclock Monitors</strong>:</p><ol><li>Open <code>CRU.exe</code> as Administrator.</li><li>Select your active display from the dropdown menu at the top.</li><li>Click <strong>Add...</strong> under the <em>Detailed resolutions</em> box.</li><li>Keep settings on &quot;Automatic&quot; and increase the refresh rate incrementally (e.g., from 60Hz to 74Hz). Click OK.</li><li>Run the included <code>restart.exe</code> (or <code>restart64.exe</code>) inside the CRU folder to reset the graphics driver.</li><li>Right-click Desktop &gt; Display Settings &gt; Advanced Display and change your refresh rate to test stability.</li></ol></div><h3 id="lightshot-lightshot-exe" tabindex="-1">Lightshot (<code>Lightshot.exe</code>) <a class="header-anchor" href="#lightshot-lightshot-exe" aria-label="Permalink to &quot;Lightshot (`Lightshot.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Lightweight screenshot program. It overrides the <code>Print Screen</code> key to allow custom cropping, highlighting, and immediate cloud uploading.</li></ul><h3 id="steam-steamsetup-exe" tabindex="-1">Steam (<code>SteamSetup.exe</code>) <a class="header-anchor" href="#steam-steamsetup-exe" aria-label="Permalink to &quot;Steam (`SteamSetup.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Installer for the Valve Steam gaming platform.</li></ul><h3 id="tetris-gameboy-tetris-gameboy-exe" tabindex="-1">Tetris GameBoy (<code>Tetris_GameBoy.exe</code>) <a class="header-anchor" href="#tetris-gameboy-tetris-gameboy-exe" aria-label="Permalink to &quot;Tetris GameBoy (`Tetris_GameBoy.exe`)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: A retro Tetris simulator. Great for checking system controller latency and responsiveness.</li></ul>',46)])])}const m=t(o,[["render",s]]);export{g as __pageData,m as default};
